    "content": "import type { RegistryItem } from \"@/registry/types\";\n\nconst accordionMeta = {\n\tname: \"accordion\",\n\ttype: \"registry:ui\",\n\tgroup: \"disclosure\",\n\tfiles: [\n\t\t{\n\t\t\ttype: \"registry:ui\",\n\t\t\tpath: \"ui/accordion/base.tsx\",\n\t\t\ttarget: \"ui/accordion.tsx\",\n\t\t},\n\t],\n\tparams: {\n\t\tstyle: {\n\t\t\tkind: \"enum\",\n\t\t\tdefault: \"default\",\n\t\t\tvalues: [\"default\", \"hammamet\"] as const,\n\t\t},\n\t},\n} satisfies RegistryItem;\n\nexport default accordionMeta;\n"
