    "target": "src/registry/ui/switch/meta.ts",
    "content": "import type { RegistryItem } from \"@/registry/types\";\n\nconst switchMeta = {\n\tname: \"switch\",\n\ttype: \"registry:ui\",\n\tgroup: \"selection-controls\",\n\tfiles: [\n\t\t{\n\t\t\ttype: \"registry:ui\",\n\t\t\tpath: \"ui/switch/base.tsx\",\n\t\t\ttarget: \"ui/switch.tsx\",\n\t\t},\n\t],\n\tregistryDependencies: [\"focus-styles\", \"field\"],\n\tparams: {\n\t\tradius: {\n\t\t\tkind: \"scalar\",\n\t\t\ttype: \"radius\",\n\t\t\tcssVar: \"--switch-radius\",\n\t\t\tdefault: \"--radius-full\",\n\t\t},\n\t\t\"card-radius\": {\n\t\t\tkind: \"scalar\",\n\t\t\ttype: \"radius\",\n\t\t\tcssVar: \"--switch-card-radius\",\n\t\t\tdefault: \"--radius-lg\",\n\t\t\tdescription: \"Radius of the switch control when it contains label content.\",\n\t\t},\n\t},\n} satisfies RegistryItem;\n\nexport default switchMeta;\n"
