    "content": "import type { RegistryItem } from \"@/registry/types\";\n\nconst tableMeta = {\n\tname: \"table\",\n\ttype: \"registry:ui\",\n\tgroup: \"containers\",\n\tfiles: [\n\t\t{\n\t\t\ttype: \"registry:ui\",\n\t\t\tpath: \"ui/table/base.tsx\",\n\t\t\ttarget: \"ui/table.tsx\",\n\t\t},\n\t],\n\tregistryDependencies: [\"checkbox\", \"focus-styles\", \"loader\"],\n} satisfies RegistryItem;\n\nexport default tableMeta;\n"
